#include <vector>
#include <algorithm>
#include <cstdlib>

long long solve(std::vector<long long> nums) {
    int n = nums.size();
    std::vector<long long> abs_sorted(n);
    for (int i = 0; i < n; ++i) {
        abs_sorted[i] = std::abs(nums[i]);
    }
    std::sort(abs_sorted.begin(), abs_sorted.end());
    long long total = 0;
    for (int i = 0; i < n; ++i) {
        long long x = abs_sorted[i];
        long long target = 2 * x;
        auto it = std::upper_bound(abs_sorted.begin() + i + 1, abs_sorted.end(), target);
        int upper = it - abs_sorted.begin();
        int count = upper - (i + 1);
        total += count;
    }
    return total;
}
