    vector<long long> abs_values;
    for (long long num : nums) {
        abs_values.push_back(abs(num));
    }
    sort(abs_values.begin(), abs_values.end());
    long long total = 0;
    for (long long i = 0; i < abs_values.size() - 1; ++i) {
